INSERT INTO `tasks_task` VALUES(6,'Lâmpada queimada no corredor do 3º andar','A lâmpada fluorescente do corredor principal do 3º andar está queimada. O local fica escuro à noite, representando risco de queda para os moradores e visitantes.','alta','aberta','2026-06-28','2026-06-25 23:09:27.833121','2026-06-25 23:09:27.833121',NULL,'Corredor 3º Andar',NULL,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',NULL);
INSERT INTO `tasks_task` VALUES(7,'Vazamento na tubulação do banheiro masculino - Térreo','Há um vazamento significativo na tubulação sob a pia do banheiro masculino do térreo. A água está se acumulando no piso e pode causar infiltração para o subsolo.','urgente','aberta','2026-06-26','2026-06-25 23:09:27.870966','2026-06-25 23:09:27.870966',NULL,'Banheiro Masculino - Térreo',NULL,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',NULL);
INSERT INTO `tasks_task` VALUES(8,'Rachadura na parede da escadaria - 2º ao 3º andar','Foi identificada uma rachadura diagonal de aproximadamente 40cm na parede da escadaria entre o 2º e 3º andar. Necessária avaliação técnica para verificar se é estética ou estrutural.','alta','alocada','2026-06-30','2026-06-25 23:09:27.894455','2026-06-25 23:09:27.894455',NULL,'Escadaria 2º-3º Andar',8,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',3);
INSERT INTO `tasks_task` VALUES(9,'Tomada danificada na sala de reuniões 201','A tomada da parede leste da sala de reuniões 201 está com a capa plástica quebrada, expondo os fios internos. Risco elétrico alto. Isolar a tomada imediatamente e agendar substituição.','urgente','alocada','2026-06-27','2026-06-25 23:09:27.924532','2026-06-25 23:09:27.924532',NULL,'Sala de Reuniões 201',4,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',NULL);
INSERT INTO `tasks_task` VALUES(10,'Limpeza do filtro do ar-condicionado - Recepção','O ar-condicionado da recepção está com o filtro visivelmente sujo, diminuindo a eficiência do aparelho e a qualidade do ar. Necessário remover, limpar e reinstalar o filtro.','normal','alocada','2026-07-02','2026-06-25 23:09:27.962548','2026-06-25 23:09:27.962548',NULL,'Recepção - Térreo',9,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',3);
INSERT INTO `tasks_task` VALUES(11,'Maçaneta quebrada na porta do almoxarifado','A maçaneta da porta do almoxarifado está solta e não trava a porta adequadamente. Substituída por modelo compatível conforme especificação do fornecedor.','normal','concluida','2026-06-24','2026-06-25 23:09:27.993314','2026-06-25 23:09:27.993314','2026-06-25 17:09:27.833121','Almoxarifado - Subsolo',10,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',3);
INSERT INTO `tasks_task` VALUES(12,'Reparo do elevador social - Painel de controle','O painel de controle interno do elevador social apresentou falha intermitente nos botões do 4º e 5º andar. Técnico especializado realizou a manutenção corretiva no circuito.','urgente','concluida','2026-06-23','2026-06-25 23:09:28.037791','2026-06-25 23:09:28.037791','2026-06-25 11:09:27.833121','Elevador Social',4,1,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',3);
INSERT INTO `tasks_task` VALUES(13,'Substituição de forro danificado por infiltração - Sala 105','O forro de gesso da sala 105 apresentou manchas de umidade e mofo decorrentes de infiltração do andar superior. Forro removido, área tratada com impermeabilizante e novo forro instalado.','alta','finalizada','2026-06-20','2026-06-25 23:09:28.077222','2026-06-25 23:09:28.077222','2026-06-22 23:09:27.833121','Sala 105 - 1º Andar',8,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',3);
INSERT INTO `tasks_task` VALUES(14,'Pintura desgastada no hall de entrada','A pintura do hall de entrada está descascando em vários pontos, especialmente próximo ao rodapé e nas quinas. Necessário lixar, aplicar massa corrida e repintar.','baixa','aberta','2026-07-10','2026-06-25 23:09:28.119363','2026-06-25 23:09:28.119363',NULL,'Hall de Entrada - Térreo',NULL,1,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',NULL);
INSERT INTO `tasks_task` VALUES(15,'Troca de lâmpadas LED na garagem','Todas as lâmpadas da garagem do subsolo foram substituídas por modelos LED de maior eficiência energética, conforme plano de modernização do condomínio.','normal','finalizada','2026-06-15','2026-06-25 23:09:28.161447','2026-06-25 23:09:28.161447','2026-06-17 23:09:27.833121','Garagem - Subsolo',4,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',NULL);
INSERT INTO `tasks_task` VALUES(16,'Revisão do sistema hidráulico do 5º andar','Moradores do 5º andar reportaram pressão de água reduzida em todas as torneiras. Necessário verificar registros, válvulas e possíveis obstruções na tubulação.','alta','alocada','2026-06-29','2026-06-25 23:09:28.210039','2026-06-25 23:09:28.210039',NULL,'5º Andar - Área Comum',7,2,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',3);
INSERT INTO `tasks_task` VALUES(17,'Instalação de corrimão na rampa de acessibilidade','A rampa de acesso para cadeirantes na entrada lateral do prédio ainda não possui corrimão. Necessário instalar corrimão duplo em aço inox conforme norma NBR 9050.','normal','alocada','2026-07-15','2026-06-25 23:09:28.242000','2026-06-26 10:59:40.348439',NULL,'Entrada Lateral - Térreo',8,1,'Bela Vista','01310-100','São Paulo','','SP','Avenida Paulista','1578',NULL);
