START TRANSACTION;

CREATE TABLE `auth_group` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `name` varchar(150) NOT NULL UNIQUE);
CREATE TABLE `auth_group_permissions` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `group_id` integer NOT NULL REFERENCES `auth_group` (`id`) DEFERRABLE INITIALLY DEFERRED, `permission_id` integer NOT NULL REFERENCES `auth_permission` (`id`) DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE `auth_permission` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `content_type_id` integer NOT NULL REFERENCES `django_content_type` (`id`) DEFERRABLE INITIALLY DEFERRED, `codename` varchar(100) NOT NULL, `name` varchar(255) NOT NULL);
CREATE TABLE `auth_user` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `password` varchar(128) NOT NULL, `last_login` datetime NULL, `is_superuser` bool NOT NULL, `username` varchar(150) NOT NULL UNIQUE, `last_name` varchar(150) NOT NULL, `email` varchar(254) NOT NULL, `is_staff` bool NOT NULL, `is_active` bool NOT NULL, `date_joined` datetime NOT NULL, `first_name` varchar(150) NOT NULL);
CREATE TABLE `auth_user_groups` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `user_id` integer NOT NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `group_id` integer NOT NULL REFERENCES `auth_group` (`id`) DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE `auth_user_user_permissions` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `user_id` integer NOT NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `permission_id` integer NOT NULL REFERENCES `auth_permission` (`id`) DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE `django_admin_log` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `object_id` text NULL, `object_repr` varchar(200) NOT NULL, `action_flag` smallint unsigned NOT NULL CHECK (`action_flag` >= 0), `change_message` text NOT NULL, `content_type_id` integer NULL REFERENCES `django_content_type` (`id`) DEFERRABLE INITIALLY DEFERRED, `user_id` integer NOT NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `action_time` datetime NOT NULL);
CREATE TABLE `django_content_type` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `app_label` varchar(100) NOT NULL, `model` varchar(100) NOT NULL);
CREATE TABLE `django_migrations` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `app` varchar(255) NOT NULL, `name` varchar(255) NOT NULL, `applied` datetime NOT NULL);
CREATE TABLE `django_session` (`session_key` varchar(40) NOT NULL PRIMARY KEY, `session_data` text NOT NULL, `expire_date` datetime NOT NULL);
CREATE TABLE `tasks_message` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `content` text NOT NULL, `created_at` datetime NOT NULL, `sender_id` integer NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `task_id` bigint NOT NULL REFERENCES `tasks_task` (`id`) DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE `tasks_notification` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `tipo` varchar(30) NOT NULL, `titulo` varchar(200) NOT NULL, `mensagem` text NOT NULL, `lida` bool NOT NULL, `created_at` datetime NOT NULL, `recipient_id` integer NOT NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `task_id` bigint NULL REFERENCES `tasks_task` (`id`) DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE `tasks_task` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `title` varchar(200) NOT NULL, `description` text NOT NULL, `priority` varchar(20) NOT NULL, `status` varchar(20) NOT NULL, `due_date` date NULL, `created_at` datetime NOT NULL, `updated_at` datetime NOT NULL, `completed_at` datetime NULL, `location` varchar(200) NOT NULL, `assigned_to_id` integer NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `created_by_id` integer NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `bairro` varchar(100) NOT NULL, `cep` varchar(9) NOT NULL, `cidade` varchar(100) NOT NULL, `complemento` varchar(100) NOT NULL, `estado` varchar(2) NOT NULL, `logradouro` varchar(200) NOT NULL, `numero` varchar(20) NOT NULL, `assigned_leader_id` integer NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE `tasks_taskevidence` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `description` text NOT NULL, `created_at` datetime NOT NULL, `task_id` bigint NOT NULL REFERENCES `tasks_task` (`id`) DEFERRABLE INITIALLY DEFERRED, `photo` varchar(100) NOT NULL);
CREATE TABLE `users_activitylog` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `action` varchar(255) NOT NULL, `role_old` varchar(50) NULL, `role_new` varchar(50) NULL, `timestamp` datetime NOT NULL, `ip_address` char(39) NULL, `admin_user_id` integer NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `target_user_id` integer NULL REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE `users_especialidade` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `nome` varchar(100) NOT NULL UNIQUE, `descricao` text NOT NULL, `created_at` datetime NOT NULL);
CREATE TABLE `users_userprofile` (`id` integer NOT NULL PRIMARY KEY AUTO_INCREMENT, `role` varchar(20) NOT NULL, `phone` varchar(20) NOT NULL, `avatar` varchar(100) NULL, `company_name` varchar(200) NOT NULL, `bio` text NOT NULL, `created_at` datetime NOT NULL, `updated_at` datetime NOT NULL, `user_id` integer NOT NULL UNIQUE REFERENCES `auth_user` (`id`) DEFERRABLE INITIALLY DEFERRED, `bairro` varchar(100) NOT NULL, `cep` varchar(9) NOT NULL, `cidade` varchar(100) NOT NULL, `complemento` varchar(100) NOT NULL, `estado` varchar(2) NOT NULL, `logradouro` varchar(255) NOT NULL, `numero` varchar(20) NOT NULL, `especialidade_id` bigint NULL REFERENCES `users_especialidade` (`id`) DEFERRABLE INITIALLY DEFERRED, `cnpj` varchar(18) NOT NULL, `cpf` varchar(14) NOT NULL);
